package com.example.petradar.api
import android.content.Context import com.example.petradar.utils.AuthManager import com.google.gson.GsonBuilder import okhttp3.OkHttpClient import okhttp3.logging.HttpLoggingInterceptor import retrofit2.Retrofit import retrofit2.converter.gson.GsonConverterFactory import java.lang.ref.WeakReference import java.util.concurrent.TimeUnit
/** * Singleton that provides the configured [ApiService] instance for the entire app. * * Main responsibilities: * - Build the HTTP client ([OkHttpClient]) with logging and authentication interceptors. * - Configure [Retrofit] with the base URL and the JSON converter (Gson). * - Expose the [ApiService] instance ready to use in repositories. * * [WeakReference] usage for context: * A weak reference to the [android.app.Application] context is stored to avoid memory leaks. * The authentication token is resolved at request time (not at construction time), * ensuring the most recent token is always used (e.g. after a refresh). * * Initialization: * Call [init] once in [com.example.petradar.PetRadarApplication.onCreate] * before making any network requests. */ object RetrofitClient {
/** Base URL of the PetRadar API (QA environment). */ const val BASE_URL = "https://api-qa.petradar-qa.org/"
/** * Weak reference to the Application context. * Used only to read the authentication token per request. * WeakReference prevents retaining the context if the process dies. */ private var appContextRef: WeakReference<Context> = WeakReference(null)
/** * Initializes the client with the application context. * Must be called in [com.example.petradar.PetRadarApplication.onCreate]. * * @param appContext Application context (NOT an Activity context). */ fun init(appContext: Context) { appContextRef = WeakReference(appContext.applicationContext) }
/** * OkHttp logging interceptor. * Level BODY: logs the URL, headers and body of each request/response. * Useful for debugging; in production this should be set to NONE. */ private val loggingInterceptor = HttpLoggingInterceptor().apply { level = HttpLoggingInterceptor.Level.BODY }
/** Gson instance without null serialization (omits null fields from JSON output). */ private val gsonNoNulls = GsonBuilder().create()
/** * HTTP client configured with: * - 30-second timeouts for connect, read and write. * - Logging interceptor. * - Authentication interceptor: adds the `Authorization: Bearer <token>` header * to every request if a token is stored in [AuthManager]. * * Created lazily (only when first needed). */ private val okHttpClient: OkHttpClient by lazy { OkHttpClient.Builder() .addInterceptor(loggingInterceptor) .connectTimeout(30, TimeUnit.SECONDS) .readTimeout(30, TimeUnit.SECONDS) .writeTimeout(30, TimeUnit.SECONDS) .addInterceptor { chain -> val requestBuilder = chain.request().newBuilder() .addHeader("Accept", "application/json")
// Resolve the token at request time to always use the most up-to-date value. appContextRef.get()?.let { ctx -> val token = AuthManager.getAuthToken(ctx) if (!token.isNullOrEmpty()) { requestBuilder.addHeader("Authorization", "Bearer $token") } }
chain.proceed(requestBuilder.build()) } .build() }
/** * Retrofit instance with the base URL and the configured HTTP client. * Lazy: built only when first accessed. */ private val retrofit: Retrofit by lazy { Retrofit.Builder() .baseUrl(BASE_URL) .client(okHttpClient) .addConverterFactory(GsonConverterFactory.create(gsonNoNulls)) .build() }
/** * Retrofit-generated implementation of the [ApiService] interface. * This is the instance used by all repositories to make HTTP requests. * Lazy: created only the first time it is accessed. */ val apiService: ApiService by lazy { retrofit.create(ApiService::class.java) } }

package com.example.petradar.api
import android.content.Context import com.example.petradar.utils.AuthManager import com.google.gson.GsonBuilder import okhttp3.OkHttpClient import okhttp3.logging.HttpLoggingInterceptor import retrofit2.Retrofit import retrofit2.converter.gson.GsonConverterFactory import java.lang.ref.WeakReference import java.util.concurrent.TimeUnit
/** * Singleton that provides the configured [ApiService] instance for the entire app. * * Provides HTTP client with logging, auth headers, and Retrofit configuration. * * WeakReference avoids memory leaks; token resolved at request time for freshness. * * Call [init] in Application.onCreate before making network requests. */ object RetrofitClient {
/** Base URL of the PetRadar API (QA environment). */ const val BASE_URL = "https://api-qa.petradar-qa.org/"
/** * Weak reference to the Application context. * Used only to read the authentication token per request. * WeakReference prevents retaining the context if the process dies. */ private var appContextRef: WeakReference<Context> = WeakReference(null)
/** * Initializes the client with the application context. * Must be called in [com.example.petradar.PetRadarApplication.onCreate]. * * @param appContext Application context (NOT an Activity context). */ fun init(appContext: Context) { appContextRef = WeakReference(appContext.applicationContext) }
/** * OkHttp logging interceptor. * Level BODY: logs the URL, headers and body of each request/response. * Useful for debugging; in production this should be set to NONE. */ private val loggingInterceptor = HttpLoggingInterceptor().apply { level = HttpLoggingInterceptor.Level.BODY }
/** Gson instance without null serialization (omits null fields from JSON output). */ private val gsonNoNulls = GsonBuilder().create()
/** * HTTP client configured with: * - 30-second timeouts for connect, read and write. * - Logging interceptor. * - Authentication interceptor: adds the `Authorization: Bearer <token>` header * to every request if a token is stored in [AuthManager]. * * Created lazily (only when first needed). */ private val okHttpClient: OkHttpClient by lazy { OkHttpClient.Builder() .addInterceptor(loggingInterceptor) .connectTimeout(30, TimeUnit.SECONDS) .readTimeout(30, TimeUnit.SECONDS) .writeTimeout(30, TimeUnit.SECONDS) .addInterceptor { chain -> val requestBuilder = chain.request().newBuilder() .addHeader("Accept", "application/json")
// Resolve the token at request time to always use the most up-to-date value. appContextRef.get()?.let { ctx -> val token = AuthManager.getAuthToken(ctx) if (!token.isNullOrEmpty()) { requestBuilder.addHeader("Authorization", "Bearer $token") } }
chain.proceed(requestBuilder.build()) } .build() }
/** * Retrofit instance with the base URL and the configured HTTP client. * Lazy: built only when first accessed. */ private val retrofit: Retrofit by lazy { Retrofit.Builder() .baseUrl(BASE_URL) .client(okHttpClient) .addConverterFactory(GsonConverterFactory.create(gsonNoNulls)) .build() }
/** * Retrofit-generated implementation of the [ApiService] interface. * This is the instance used by all repositories to make HTTP requests. * Lazy: created only the first time it is accessed. */ val apiService: ApiService by lazy { retrofit.create(ApiService::class.java) } }

package com.example.petradar.repository

import com.example.petradar.api.RetrofitClient
import com.example.petradar.api.UserPetCreateModel
import com.example.petradar.api.UserPetUpdateModel
import com.example.petradar.api.UserPetViewModel
import okhttp3.MultipartBody
import retrofit2.Response

/**
 * Repository that centralises all CRUD operations for pets with the API.
 *
 * Acts as the intermediary between ViewModels and [RetrofitClient.apiService].
 * All functions are `suspend` and must be called from a coroutine.
 */
class PetRepository {

    /** Reference to the Retrofit service obtained from the [RetrofitClient] singleton. */
    private val apiService = RetrofitClient.apiService

    /**
     * Retrieves the list of pets belonging to a user.
     * Endpoint: GET /api/UserPets/user/{userId}
     *
     * @param userId Owner user ID.
     * @return List of [UserPetViewModel]; may be empty if the user has no pets.
     */
    suspend fun getPetsByUserId(userId: Long): Response<List<UserPetViewModel>> {
        return apiService.getUserPetsByUserId(userId)
    }

    /**
     * Retrieves the details of a pet by its ID.
     * Endpoint: GET /api/UserPets/{id}
     *
     * @param petId Pet ID. HTTP 404 if not found.
     */
    suspend fun getPetById(petId: Long): Response<UserPetViewModel> {
        return apiService.getUserPetById(petId)
    }

    /**
     * Creates a new pet in the system.
     * Endpoint: POST /api/UserPets
     *
     * @param request Data for the new pet ([UserPetCreateModel]).
     * @return HTTP 201 Created with no body on success.
     */
    suspend fun createPet(request: UserPetCreateModel): Response<Unit> {
        return apiService.createUserPet(request)
    }

    /**
     * Updates an existing pet's data.
     * Endpoint: PUT /api/UserPets/{id}
     *
     * @param petId   ID of the pet to update.
     * @param request Fields to modify ([UserPetUpdateModel]); null fields are ignored.
     * @return HTTP 204 No Content on success.
     */
    suspend fun updatePet(petId: Long, request: UserPetUpdateModel): Response<Unit> {
        return apiService.updateUserPet(petId, request)
    }

    /**
     * Deletes a pet from the system.
     * Endpoint: DELETE /api/UserPets/{id}
     *
     * Note: the local photo associated with the pet should also be removed
     * from [com.example.petradar.utils.PetPhotoStore] in the ViewModel.
     *
     * @param petId ID of the pet to delete.
     * @return HTTP 204 No Content on success.
     */
    suspend fun deletePet(petId: Long): Response<Unit> {
        return apiService.deleteUserPet(petId)
    }

    /**
     * Uploads or replaces the pet's main picture.
     * Endpoint: PUT /api/UserPets/{id}/mainpicture
     */
    suspend fun uploadPetMainPicture(petId: Long, filePart: MultipartBody.Part): Response<Unit> {
        return apiService.uploadPetMainPicture(petId, filePart)
    }
}

package com.example.petradar.repository

import com.example.petradar.api.RetrofitClient
import com.example.petradar.api.UserPetCreateModel
import com.example.petradar.api.UserPetUpdateModel
import com.example.petradar.api.UserPetViewModel
import okhttp3.MultipartBody
import retrofit2.Response

/**
 * Repository that centralises all CRUD operations for pets with the API.
 *
 * Acts as the intermediary between ViewModels and [RetrofitClient.apiService].
 * All functions are `suspend` and must be called from a coroutine.
 */
class PetRepository {

    /** Reference to the Retrofit service obtained from the [RetrofitClient] singleton. */
    private val apiService = RetrofitClient.apiService

    suspend fun getPetsByUserId(userId: Long): Response<List<UserPetViewModel>> {
        return apiService.getUserPetsByUserId(userId)
    }

    suspend fun getPetById(petId: Long): Response<UserPetViewModel> {
        return apiService.getUserPetById(petId)
    }

    suspend fun createPet(request: UserPetCreateModel): Response<Unit> {
        return apiService.createUserPet(request)
    }

    suspend fun updatePet(petId: Long, request: UserPetUpdateModel): Response<Unit> {
        return apiService.updateUserPet(petId, request)
    }

    suspend fun deletePet(petId: Long): Response<Unit> {
        return apiService.deleteUserPet(petId)
    }

    suspend fun uploadPetMainPicture(petId: Long, filePart: MultipartBody.Part): Response<Unit> {
        return apiService.uploadPetMainPicture(petId, filePart)
    }
}

