data class LostReportFormData(
    val latitude: Double,
    val longitude: Double,
    val addressText: String?,
    val description: String?,
    val incidentDateIso: String,
    val hasCollar: Boolean,
    val hasTag: Boolean,
    val searchRadiusMeters: Int,
    val useAlternateContact: Boolean,
